  return { workspaceId: "workspace_" + userId };
}

async function sendWelcomeEmail(email: string) {
  "use step";
  console.log("send welcome email", email);
}

export async function welcomeWorkflow(input: { userId: string; email: string }) {
  "use workflow";
  console.log("start welcome workflow", input.userId);

  const workspace = await createWorkspace(input.userId);
  await sendWelcomeEmail(input.email);

  return workspace;
}

import { start } from "workflow/api";
import { NextResponse } from "next/server";

import { welcomeWorkflow } from "@/workflows/welcome";

export async function POST(request: Request) {
  let input: unknown;

  try {
    input = await request.json();
  } catch {
    return NextResponse.json({ error: "Invalid JSON body" }, { status: 400 });
  }

  const run = await start(welcomeWorkflow, [input]);

  return NextResponse.json({ runId: run.runId });
}

const checks = [
  "Install provider package and configure env",
  "Run the local example path",
  "Add auth, retries, and audit events before production",
];

export default function VercelWorkflowsPage() {
  return (
    <main className="flex flex-col gap-6 p-6">
      <div>
        <h1 className="text-2xl font-semibold">Vercel Workflows</h1>
        <p className="text-muted-foreground">Durable functions with step boundaries, retries, logging, and run IDs.</p>
      </div>
      <div className="grid gap-3">
        {checks.map((check) => (
          <div key={check} className="rounded-lg border p-4 text-sm">{check}</div>
        ))}
      </div>
    </main>
  );
}
